-- ============================================================================
-- Marketplace inventory — coaching-generic Playbooks & Knowledge packs (Wave 2).
--
-- 8 KB packs (24 docs), authored by the writing crew and passed by the §2/§3
-- compliance officer (zero consumer-finance vocab; mogul-founder voice; genuinely
-- useful, no placeholders — §2/§3/§13). Each is item_type='kb_pack', config_only,
-- category 'playbooks', free + opt-in (never a default). They install through the
-- already-proven marketplace-install edge path (Voyage embed → tenant_knowledge_*
-- → finalize RPC), so a tenant that installs one genuinely seeds a retrievable
-- knowledge brain into their Paige. Takes the shelf from 2 real items to 10.
-- ============================================================================

BEGIN;

DO $seed$
DECLARE _vendor uuid; _item uuid; _ver uuid;
BEGIN
  SELECT id INTO _vendor FROM public.marketplace_vendors WHERE slug='paige';
  INSERT INTO public.marketplace_items (slug,item_type,vendor_id,origin,name,tagline,description,category,icon,scope,status,default_for_new_tenants)
  VALUES ('discovery_call_mastery','kb_pack',_vendor,'first_party','Discovery Call Mastery','Turn the first conversation into a signed client.','A working system for running discovery calls that qualify hard, surface real problems, and convert to proposals fast.','playbooks','PhoneCall','public','listed',false)
  ON CONFLICT (slug) DO NOTHING RETURNING id INTO _item;
  IF _item IS NOT NULL THEN
    INSERT INTO public.marketplace_item_versions (item_id,semver,status,payload_class,install_manifest,published_at)
    VALUES (_item,'1.0.0','published','config_only', '{"kb_pack": {"docs": [{"title": "Running a Discovery Call That Closes", "category": "playbooks", "tags": ["discovery", "sales", "qualification"], "content": "A discovery call is not a pitch. It is a diagnosis. The prospect closes themselves when they hear their own problem stated back sharper than they could say it. Your job is to run the room, not fill the silence.\n\nStructure the 30-45 minutes in five moves:\n\n1. Frame (2 min). Set the agenda out loud: \"I want to understand where you are, where you''re trying to get, and what''s in the way. If it''s a fit, I''ll tell you exactly how I''d help. If it''s not, I''ll tell you that too.\" This gives you permission to ask hard questions and signals you''re willing to walk.\n\n2. Current state (10 min). Where are they now, in their words and their numbers? Get specifics, not adjectives. \"Slow\" is useless; \"three months behind on the launch\" is a problem you can price.\n\n3. Desired state and cost of inaction (10 min). What does solved look like, and what does staying stuck cost them monthly? The gap between these two is your fee.\n\n4. Fit and decision process (5 min). Who else decides? What''s the timeline? What budget range have they set aside?\n\n5. Clear next step (3 min). Never end on \"I''ll follow up.\" Book the next action live.\n\nTalk less than 30% of the time. The person doing the talking feels understood, and understood people buy."}, {"title": "A Discovery Question Bank by Objection", "category": "playbooks", "tags": ["discovery", "objections", "questions"], "content": "Objections aren''t walls; they''re missing information you should have surfaced on the call. Map your questions to the objection you want to preempt.\n\nAgainst \"I need to think about it\" (no real urgency): \"What happens if this is still unsolved six months from now?\" / \"What made you take this call today specifically?\" / \"On a scale of drop-everything to nice-to-have, where does fixing this sit?\"\n\nAgainst \"It''s too expensive\" (value unclear): \"What''s this problem costing you every month it stays open?\" / \"If we hit the outcome we just described, what''s that worth to the business?\" / \"What have you already spent trying to solve this another way?\"\n\nAgainst \"I need to ask my partner/board\" (wrong person): \"Who else feels this problem day to day?\" / \"When you''ve bought something like this before, who signs off?\" / \"What would they need to see to say yes?\"\n\nAgainst \"Now isn''t the right time\" (priority conflict): \"What''s ahead of this on your list right now?\" / \"What would have to be true for this to become the priority?\"\n\nAgainst \"How do I know it''ll work?\" (risk): \"What would proof look like to you in the first 30 days?\" / \"What''s made past attempts fail?\"\n\nAsk these during discovery, not at the close. By the time you name your fee, the prospect has already argued your case for you."}, {"title": "From Discovery to Proposal in 24 Hours", "category": "playbooks", "tags": ["proposals", "follow-up", "closing"], "content": "Speed is a signal. A proposal that lands the next morning tells the prospect exactly how it feels to work with you: sharp, responsive, on it. Wait a week and the emotion from the call is gone, and emotion is what buys.\n\nCapture while the call is warm. In the last two minutes, read back what you heard: \"So the real problem is X, the goal is Y by this date, and doing nothing costs you Z a month. Did I get that right?\" Their confirmation is the spine of the proposal. Write it down verbatim.\n\nWithin an hour, draft the one-pager. Not a brochure. Four blocks: (1) the problem in their words, (2) the outcome you''ll deliver and by when, (3) exactly what you''ll do, in plain scope, (4) the investment and the first step. Price the outcome from block three of your discovery, not your hours.\n\nSend within 24 hours with a two-line note: \"Here''s what I heard and how I''d solve it. I blocked time Thursday to walk you through it live.\" Attach a booked slot, not an open invitation to disappear.\n\nAlways present the proposal on a call, never over email alone. A document can''t answer the question that''s about to kill the deal; you can. If they insist on reviewing solo, send it, then hold your calendar time and confirm the review call before you hang up.\n\nOne offer, one price, one next step. Choice at this stage creates hesitation, and hesitation is where deals go to die."}]}, "functions": []}'::jsonb, now()) RETURNING id INTO _ver;
    UPDATE public.marketplace_items SET current_version_id=_ver WHERE id=_item;
  END IF;
END $seed$;

DO $seed$
DECLARE _vendor uuid; _item uuid; _ver uuid;
BEGIN
  SELECT id INTO _vendor FROM public.marketplace_vendors WHERE slug='paige';
  INSERT INTO public.marketplace_items (slug,item_type,vendor_id,origin,name,tagline,description,category,icon,scope,status,default_for_new_tenants)
  VALUES ('client_retention_playbook','kb_pack',_vendor,'first_party','Client Retention Playbook','Keep the clients you already earned.','A field guide to catching at-risk clients before they churn and converting shaky engagements into renewals.','playbooks','PhoneCall','public','listed',false)
  ON CONFLICT (slug) DO NOTHING RETURNING id INTO _item;
  IF _item IS NOT NULL THEN
    INSERT INTO public.marketplace_item_versions (item_id,semver,status,payload_class,install_manifest,published_at)
    VALUES (_item,'1.0.0','published','config_only', '{"kb_pack": {"docs": [{"title": "Spotting an At-Risk Client Early", "category": "playbooks", "tags": ["retention", "churn", "early-warning"], "content": "By the time a client says \"we need to talk,\" the decision is usually made. Retention is won in the weeks before that, reading the signals while you can still act on them.\n\nWatch for four behavior shifts:\n\n1. Response lag. Replies that used to come same-day now take three. Meetings get rescheduled, then attended by a junior instead of the decision-maker. Engagement is the first thing to drop and the earliest tell.\n\n2. Scope quietly shrinking. They stop bringing you the big questions and start using you for the small ones. When a strategic relationship gets treated like a task rabbit, the perceived value has slipped.\n\n3. Outcome amnesia. Early on they could name what you''d delivered. Now they ask \"what did we do last month again?\" That''s not forgetfulness; it''s a value story that stopped being told.\n\n4. New voices in the room. A procurement contact, a new hire \"reviewing vendors,\" a sudden interest in month-to-month terms. Someone is being asked to justify the spend.\n\nBuild a simple health score you update after every touchpoint: green (engaged, seeing results), yellow (one or two signals), red (multiple signals or a missed outcome). Any move to yellow triggers a check-in that week, not next quarter. The cost of a proactive conversation is 20 minutes. The cost of a surprise cancellation is the whole account."}, {"title": "The Mid-Engagement Check-In Script", "category": "playbooks", "tags": ["retention", "check-in", "client-success"], "content": "Most people only call a client when something''s wrong or when it''s renewal time. That trains the client to associate your voice with a bill. The mid-engagement check-in breaks that pattern: a deliberate conversation, halfway through the term, with no agenda except the relationship.\n\nBook it as its own 30-minute call, not a tack-on to a working session. The framing when you invite them: \"I want to step back from the day-to-day and make sure this is delivering what you actually need.\" That sentence alone raises retention, because almost no one else does it.\n\nRun four questions:\n\n1. \"Where are you seeing the most value from our work so far?\" Let them build your renewal case in their own words. Write down exactly what they say.\n\n2. \"What''s one thing you expected that we haven''t gotten to yet?\" This surfaces the quiet disappointment before it becomes the reason they leave.\n\n3. \"If you were pitching this to your team, how would you describe the return?\" If they can''t answer, you have a value-communication gap to close now.\n\n4. \"What would make the second half even more worth it?\" You just turned a check-in into an expansion conversation.\n\nClose by reflecting back the wins they named and confirming one concrete adjustment for the back half. Send a two-line recap the same day. You''ve now given them a reason to stay that they articulated themselves."}, {"title": "Turning a Wobble Into a Renewal", "category": "playbooks", "tags": ["retention", "renewal", "recovery"], "content": "A wobble is a client who''s gone yellow: quieter, questioning value, maybe floating \"let''s revisit at the end of the term.\" This is not a lost account. It''s an invitation to a conversation you should welcome, because handled well, a recovered client renews harder than one who never doubted.\n\nMove fast and go direct. Don''t paper over it with a cheerful email. Call and name it: \"I''ve felt us drift from where we started, and I care too much about the outcome to let that slide. Can we talk straight for 20 minutes?\" Naming the tension defuses it. Avoiding it confirms their fear.\n\nOn the call, listen first and resist defending. Ask \"what''s changed for you since we started?\" and let the real reason surface. Usually it''s one of three: results feel slow, priorities shifted internally, or they''ve lost the thread on what you''re actually delivering. Each has a different fix, and you can''t pick until you know which.\n\nThen re-contract out loud. Reset expectations for the remaining term, name one specific win you''ll drive in the next 30 days, and put it in writing. A concrete near-term commitment rebuilds belief faster than any discount.\n\nDo not lead with a price cut. Cutting price to save an account teaches the client that your fee was soft and trains them to wobble again at every renewal. Lead with renewed value and a clear plan. Save the commercial lever for genuine scope change, never as an apology."}]}, "functions": []}'::jsonb, now()) RETURNING id INTO _ver;
    UPDATE public.marketplace_items SET current_version_id=_ver WHERE id=_item;
  END IF;
END $seed$;

DO $seed$
DECLARE _vendor uuid; _item uuid; _ver uuid;
BEGIN
  SELECT id INTO _vendor FROM public.marketplace_vendors WHERE slug='paige';
  INSERT INTO public.marketplace_items (slug,item_type,vendor_id,origin,name,tagline,description,category,icon,scope,status,default_for_new_tenants)
  VALUES ('proposal_and_pricing','kb_pack',_vendor,'first_party','Proposals & Pricing','Win the yes before you name the number.','A working playbook for framing value, structuring proposals in tiers, and holding your price when a client pushes back.','playbooks','FileText','public','listed',false)
  ON CONFLICT (slug) DO NOTHING RETURNING id INTO _item;
  IF _item IS NOT NULL THEN
    INSERT INTO public.marketplace_item_versions (item_id,semver,status,payload_class,install_manifest,published_at)
    VALUES (_item,'1.0.0','published','config_only', '{"kb_pack": {"docs": [{"title": "Anchoring Value Before You Name a Price", "category": "playbooks", "tags": ["pricing", "sales-conversations", "positioning"], "content": "Price feels expensive only when the client can''t see what they''re getting for it. The fix is sequencing: establish the value of the outcome before the number ever enters the room.\n\nStart by getting the client to say the cost of their current situation out loud. Ask what the problem is costing them now — in lost time, stalled revenue, missed opportunities, or the drag of doing it themselves. Let them do the math. A client who tells you the status quo costs them 20 hours a month has just built your justification for you.\n\nNext, connect your work directly to that number. Don''t describe your deliverables (\"six sessions, two audits, a plan\"); describe the movement from where they are to where they want to be. Deliverables are what you do. Outcomes are what they buy.\n\nOnly then name the price — and name it as a fraction of the value, not a standalone figure. \"You told me this is costing you five figures a quarter. The engagement is X.\" The number now sits next to a bigger number, so it reads as a return, not an expense.\n\nTwo rules. Never apologize for the price or soften it with nervous filler; say it plainly and stop talking. And never quote before you''ve surfaced the cost of inaction — a price with no anchor is just a number the client compares to zero. Anchor first, quote second, then let the silence work."}, {"title": "The Three-Tier Proposal Structure", "category": "playbooks", "tags": ["proposals", "pricing", "packaging"], "content": "A single-price proposal forces a yes-or-no. Three tiers turn the decision into \"which one\" — and clients who are choosing how much to buy have already decided to buy.\n\nBuild three options, not five. More than three creates paralysis. Name them by the outcome each delivers, not by size (\"Foundation / Momentum / Partner\" beats \"Basic / Pro / Premium\"). Order them high to low or low to high consistently, and make the middle tier the one you actually want most clients to land on.\n\nThe anatomy that works:\n\n- Tier 1 (entry): solves the core problem, nothing extra. Real and deliverable — never a strawman you''d be unhappy to sell.\n- Tier 2 (target): the core plus the things most clients end up needing anyway — more access, faster turnaround, a wider scope. Price it so the jump from Tier 1 feels small relative to what''s added.\n- Tier 3 (premium): everything, plus depth or speed only some clients want. Its real job is to make Tier 2 look reasonable. A few clients will surprise you and take it.\n\nPrice the tiers so the gaps tell a story: a modest step from 1 to 2, a larger step from 2 to 3. That contrast pulls the eye to the middle.\n\nPresent tiers live if you can, walking the client through the trade-offs, rather than emailing a document to be read alone. And put a clear recommendation in writing — \"Most clients in your situation choose Momentum\" — so the client isn''t left to guess which one is for them."}, {"title": "Handling Price Pushback Without Discounting", "category": "playbooks", "tags": ["objections", "pricing", "negotiation"], "content": "\"That''s more than I expected\" is not a rejection. It''s a request for more certainty. Discounting answers a question the client didn''t ask and quietly signals your first number was inflated.\n\nStart by getting curious instead of defensive. Ask, \"When you say more than expected — more than budgeted, or more than you thought the work was worth?\" Those are different problems. A budget gap is about timing and scope. A value gap means you haven''t finished making the case. Diagnose before you respond.\n\nIf it''s a value gap, go back to the outcome and the cost of staying stuck. Don''t repeat the price louder — re-anchor it against what the problem is costing them.\n\nIf it''s a genuine budget constraint, adjust scope, never rate. Move a tier down, extend the timeline, remove a deliverable — change what they get for less, so your price-per-value holds. The moment you cut the rate while keeping the scope, you''ve taught the client that your prices are negotiable fiction and every future number invites a haggle.\n\nKeep a few honest trades ready: a smaller starting engagement that can expand, a phased rollout, a payment schedule spread over the term. Each preserves your rate while meeting a real constraint.\n\nAnd know when to let a deal go. A client who only buys at a discount becomes a client who expects one forever, refers other discount-seekers, and treats the work as cheap. Hold the line, offer a smaller real option, and walk if it isn''t a fit. Your price protects the clients who paid it in full."}]}, "functions": []}'::jsonb, now()) RETURNING id INTO _ver;
    UPDATE public.marketplace_items SET current_version_id=_ver WHERE id=_item;
  END IF;
END $seed$;

DO $seed$
DECLARE _vendor uuid; _item uuid; _ver uuid;
BEGIN
  SELECT id INTO _vendor FROM public.marketplace_vendors WHERE slug='paige';
  INSERT INTO public.marketplace_items (slug,item_type,vendor_id,origin,name,tagline,description,category,icon,scope,status,default_for_new_tenants)
  VALUES ('referral_and_testimonial_engine','kb_pack',_vendor,'first_party','Referrals & Testimonials','Turn every win into the next three clients.','A practical system for asking for referrals at the right moment, getting testimonials people actually say yes to, and converting results into case studies that sell.','playbooks','FileText','public','listed',false)
  ON CONFLICT (slug) DO NOTHING RETURNING id INTO _item;
  IF _item IS NOT NULL THEN
    INSERT INTO public.marketplace_item_versions (item_id,semver,status,payload_class,install_manifest,published_at)
    VALUES (_item,'1.0.0','published','config_only', '{"kb_pack": {"docs": [{"title": "When and How to Ask for the Referral", "category": "playbooks", "tags": ["referrals", "client-growth", "timing"], "content": "Most referrals never happen because the ask never comes — or comes at a dead moment, buried in an invoice or a year-end email. Referrals are a timing game before they''re a wording game.\n\nAsk at the peak of felt value: right after a client hits a result, praises your work unprompted, or renews. That''s when the win is vivid and they''re primed to talk about it. Waiting until the engagement ends means asking when the emotion has already cooled.\n\nMake the ask specific, not broad. \"Do you know anyone who''d benefit from this?\" gets a vague \"I''ll think about it,\" because you''ve handed the client a research project. Instead: \"Who''s one person you know who''s dealing with the same thing you were three months ago?\" One person, a concrete situation — now they can actually picture a name.\n\nRemove the work of connecting. Offer to write a short intro they can forward, so all they do is add a name and hit send. The easier you make the motion, the more often it completes.\n\nThree rules. Ask in person or by voice when you can — a warm ask converts far better than a cold form. Never make it feel transactional or desperate; you''re offering to help someone they know, not begging for leads. And ask consistently, not once. A referral habit built into your natural check-ins produces a steady stream; a one-time push produces one awkward conversation. Bake the ask into the moments you''re already having."}, {"title": "The Testimonial Request That Gets a Yes", "category": "playbooks", "tags": ["testimonials", "social-proof", "client-communication"], "content": "\"Would you mind writing a testimonial?\" fails for one reason: it hands the client a blank page and a chore. They want to help, but staring at nothing, they stall — and your request quietly dies in their inbox.\n\nThe fix is to remove the blank page. Don''t ask them to write; ask them a few questions and write it for them to approve.\n\nSend three or four short prompts that pull a story, not adjectives:\n\n- What was going on before we started working together?\n- What made you decide to move forward?\n- What''s different now — and can you point to anything specific?\n- What would you say to someone on the fence?\n\nThose questions produce a before/after with a concrete result in the middle, which is the only kind of testimonial that persuades anyone. \"They were great to work with\" convinces no one. \"I was drowning in admin; now I get four hours a week back\" sells.\n\nEven better, capture it in conversation. On your next call, ask the questions live, take notes, then draft the testimonial from their words and send it back: \"Here''s what I heard — edit anything that''s off and okay it.\" You''ve turned a writing assignment into a two-minute approval.\n\nAlways get explicit sign-off on the final wording and how you''ll use it — name, photo, company, where it appears. And ask while the result is fresh. A testimonial requested six months after the win is a memory; requested the week it lands, it''s a story they''re still excited to tell."}, {"title": "Turning a Win Into a Case Study", "category": "playbooks", "tags": ["case-studies", "social-proof", "content"], "content": "A testimonial says you''re good. A case study proves it — with a situation, a decision, and a measurable result a prospect can map onto their own problem. It''s the difference between a compliment and evidence.\n\nUse a simple three-part spine: the situation, the work, the result. Open with where the client started and what was at stake — specific enough that a similar prospect thinks, \"That''s me.\" Then the work: what you actually did and why, kept concrete but not exhaustive. Close with the outcome, and put a number on it whenever you can — hours saved, response times, retention, pipeline, whatever your work moves. If you can''t quantify, capture a vivid before/after in the client''s own words.\n\nGather the raw material at the moment of the win, not months later when the details have blurred. Ask what changed and how they''d measure it. Pull real figures where the client will let you; approximate honestly where they won''t (\"cut onboarding time by roughly half\") and never invent numbers — a fabricated result is a liability the first time a prospect asks about it.\n\nGet written permission on every detail you publish — name, company, figures, logo. Some clients will share results but not their name; a strong anonymized case study (\"a consulting firm in a regulated industry\") still works.\n\nThen make one story earn its keep everywhere: the full write-up on your site, a short version in proposals for similar prospects, a pull-quote in email, a talking point on sales calls. One well-documented win becomes proof you reuse for years."}]}, "functions": []}'::jsonb, now()) RETURNING id INTO _ver;
    UPDATE public.marketplace_items SET current_version_id=_ver WHERE id=_item;
  END IF;
END $seed$;

DO $seed$
DECLARE _vendor uuid; _item uuid; _ver uuid;
BEGIN
  SELECT id INTO _vendor FROM public.marketplace_vendors WHERE slug='paige';
  INSERT INTO public.marketplace_items (slug,item_type,vendor_id,origin,name,tagline,description,category,icon,scope,status,default_for_new_tenants)
  VALUES ('renewals_and_offboarding','kb_pack',_vendor,'first_party','Renewals & Offboarding','Keep the clients worth keeping, and part with the rest so well they still send you business.','Playbooks for running renewal conversations, offboarding clients gracefully enough to earn referrals, and winning back the ones who lapsed.','playbooks','RefreshCw','public','listed',false)
  ON CONFLICT (slug) DO NOTHING RETURNING id INTO _item;
  IF _item IS NOT NULL THEN
    INSERT INTO public.marketplace_item_versions (item_id,semver,status,payload_class,install_manifest,published_at)
    VALUES (_item,'1.0.0','published','config_only', '{"kb_pack": {"docs": [{"title": "The Renewal Conversation", "category": "playbooks", "tags": ["renewals", "retention", "client-conversations"], "content": "A renewal is won or lost weeks before you ask the question. If the client can''t name what changed because of your work, no pitch saves it. So start the conversation by making the results undeniable.\n\nOpen the renewal talk 30 to 45 days before the term ends, never in the final week when it reads as a scramble. Bring a one-page recap: where they were when you started, what you did together, and the specific outcomes. Use their numbers and their words, pulled from your notes and check-ins, not vague claims of progress.\n\nThen shift from past to future. Ask directly: \"What do you want the next chapter to look like?\" Their answer tells you whether to renew flat, expand scope, or right-size down. Let them talk first. The renewal offer should map to the goal they just named, not the package they happen to be on.\n\nName the momentum they''d lose by stopping. People underweight the cost of pausing; make it concrete. \"You''ve built the habit of weekly reviews. The month you drop it is the month things slide.\"\n\nHandle price before they raise it. If you''re raising rates, say so plainly and tie it to the expanded value, not inflation.\n\nClose by asking for the decision, not hinting at it: \"Do you want to keep going?\" Silence after the ask is the client thinking. Let them."}, {"title": "A Graceful Offboarding That Earns Referrals", "category": "playbooks", "tags": ["offboarding", "referrals", "client-experience"], "content": "How a relationship ends is what the client remembers and repeats. A client who leaves feeling finished and celebrated becomes a referral source. One who leaves feeling dropped becomes a warning to their network. The last impression is the loudest.\n\nRun a real closing session, not a canceled subscription. Walk back through the arc of the work: where they started, what they built, what''s now theirs to keep. This turns \"it''s over\" into \"you graduated,\" and it makes the value legible one more time, right when they''re deciding what to tell people.\n\nHand over a clean asset. A short document with their key results, the frameworks you used, the decisions still open, and what to watch for next. It costs you an hour and it''s the thing they''ll forward to a peer who asks who they worked with.\n\nAsk two things while goodwill is at its peak. First, honest feedback: \"What worked, what would you change?\" This sharpens your practice and signals you''re still invested. Second, the referral, made specific: \"Who do you know facing what you were facing six months ago?\" Specificity beats \"keep me in mind\" every time.\n\nLeave the door open without desperation. \"If the next challenge is a fit, you know where I am.\" Then actually stay in touch on a light cadence. A clean exit is not a lost client; it''s a client between engagements."}, {"title": "A Win-Back Sequence for Lapsed Clients", "category": "playbooks", "tags": ["win-back", "re-engagement", "sequences"], "content": "Lapsed clients are your warmest pipeline. They already know your work, already trust you, and already paid you once. Winning one back costs a fraction of finding a stranger. But a win-back only works if it leads with them, not with your calendar gap.\n\nSegment first. A client who finished their goals and moved on needs a different message than one who drifted or left frustrated. Don''t send the same note to both. If someone left unhappy, address it directly before pitching anything; skipping the friction insults their memory.\n\nRun a three-touch sequence over two to three weeks. Touch one gives pure value, no ask: a relevant resource, an idea for their situation, a genuine \"thought of you when I saw this.\" Touch two opens a door with a light check-in: \"How did the thing you were working on turn out?\" Curiosity, not a sales script. Touch three, only if they''ve engaged, makes a specific offer tied to what you now know about where they are.\n\nMake the return easy. Returning clients shouldn''t re-onboard from zero. Offer a shortened re-entry that acknowledges the history: \"We can pick up close to where we left off.\"\n\nKnow when to stop. If all three touches land silent, move them to a quarterly newsletter cadence and let go. Chasing is the fastest way to become a name they mute."}]}, "functions": []}'::jsonb, now()) RETURNING id INTO _ver;
    UPDATE public.marketplace_items SET current_version_id=_ver WHERE id=_item;
  END IF;
END $seed$;

DO $seed$
DECLARE _vendor uuid; _item uuid; _ver uuid;
BEGIN
  SELECT id INTO _vendor FROM public.marketplace_vendors WHERE slug='paige';
  INSERT INTO public.marketplace_items (slug,item_type,vendor_id,origin,name,tagline,description,category,icon,scope,status,default_for_new_tenants)
  VALUES ('objection_handling','kb_pack',_vendor,'first_party','Objection Handling','The objection is not a wall. It is the client telling you exactly what they need to hear next.','Field-tested playbooks for the objections every client-based practice hears, how to reframe stalling, and how to hold your price without caving.','playbooks','RefreshCw','public','listed',false)
  ON CONFLICT (slug) DO NOTHING RETURNING id INTO _item;
  IF _item IS NOT NULL THEN
    INSERT INTO public.marketplace_item_versions (item_id,semver,status,payload_class,install_manifest,published_at)
    VALUES (_item,'1.0.0','published','config_only', '{"kb_pack": {"docs": [{"title": "The Five Objections Every Practice Hears", "category": "playbooks", "tags": ["objections", "sales", "closing"], "content": "Almost every hesitation a prospect raises is one of five, and each has a different root. Mislabel the objection and you answer the wrong question, which reads as not listening.\n\nOne: price. \"It''s too expensive.\" Usually not about the number; it''s about unclear value. The fix is to re-anchor on the outcome and what staying stuck costs, not to discount.\n\nTwo: time. \"I''m too busy right now.\" Often means they don''t yet see the work as urgent or as time-saving. Show how your engagement gives time back rather than taking more.\n\nThree: trust. \"How do I know this works?\" A request for proof. Answer with specific results from people like them, and with exactly how you operate, so the process feels safe.\n\nFour: authority. \"I need to talk to my partner/team.\" Sometimes real, sometimes a soft no. Ask what they''d need to walk into that conversation confident, then arm them for it.\n\nFive: fit. \"I''m not sure this is right for me.\" The deepest one. They don''t see themselves in your solution. Reflect their exact situation back until they recognize it.\n\nBefore you respond to any objection, ask one clarifying question. \"When you say expensive, expensive compared to what?\" The answer tells you which of the five you''re actually holding, and half the time the client talks themselves past it."}, {"title": "Reframing ''I Need to Think About It''", "category": "playbooks", "tags": ["objections", "stalling", "decisions"], "content": "\"Let me think about it\" is rarely about thinking. It''s an exit from a decision that feels uncomfortable, and if you accept it at face value the conversation dies in a follow-up graveyard. Your job is to surface the real hesitation without pushing.\n\nStart by agreeing. \"Totally fair, this is a real decision.\" Pressure makes people cling to the stall; permission makes them relax and tell you more. Then get specific: \"When you think it over, what''s the part you''ll be weighing?\" This one question converts a vague delay into a named objection you can actually work with, whether it''s price, timing, or a doubt they didn''t want to say out loud.\n\nListen for which of two things is happening. Either they lack information, in which case give them exactly what''s missing and offer to decide together now. Or they lack conviction, in which case revisit whether the outcome genuinely matters to them, because if it doesn''t, no amount of follow-up will fix that.\n\nOffer a smaller yes. If a full commitment feels like too much, propose a defined first step that lets them experience the work before betting everything. Momentum beats deliberation.\n\nIf they still need time, set a real next step with a date: \"Let''s talk Thursday.\" An open-ended \"I''ll reach out\" is where deals go to disappear. You control the next touch, not their inbox."}, {"title": "Budget Objections Without Dropping Price", "category": "playbooks", "tags": ["pricing", "objections", "value"], "content": "The instant you discount to save a deal, you tell the client your first price was made up, and you train them to push every time. Holding price is not stubbornness; it''s respect for your own work and theirs. The move is to change the conversation from cost to value, not from higher to lower.\n\nFirst, separate \"can''t afford\" from \"don''t see the value.\" They sound identical and need opposite responses. Ask: \"Is it that the timing''s tight, or that you''re not sure it''s worth it?\" If it''s worth, you have a value gap to close. If it''s timing, you have a structure problem to solve.\n\nFor a value gap, re-anchor on the outcome and the cost of inaction. What is the problem costing them each month it goes unsolved? When the price sits next to that number, it usually shrinks. Make the return concrete and specific to their situation.\n\nFor a genuine timing problem, adjust structure, not price. Offer a payment plan, a phased scope, or a smaller starting engagement that fits now and expands later. The value per unit of work stays intact; only the packaging flexes.\n\nIf you truly must move on price, get something back: a longer commitment, a case study, an introduction. A concession for nothing is a discount; a concession for something is a negotiation.\n\nAnd be willing to hear no. A client who only says yes at half price was never going to value the work anyway."}]}, "functions": []}'::jsonb, now()) RETURNING id INTO _ver;
    UPDATE public.marketplace_items SET current_version_id=_ver WHERE id=_item;
  END IF;
END $seed$;

DO $seed$
DECLARE _vendor uuid; _item uuid; _ver uuid;
BEGIN
  SELECT id INTO _vendor FROM public.marketplace_vendors WHERE slug='paige';
  INSERT INTO public.marketplace_items (slug,item_type,vendor_id,origin,name,tagline,description,category,icon,scope,status,default_for_new_tenants)
  VALUES ('accountability_and_followthrough','kb_pack',_vendor,'first_party','Accountability & Follow-Through','Turn what happens in the session into what actually gets done between them.','A practitioner''s playbook for building between-session accountability, running a follow-through nudge cadence, and re-engaging clients who go quiet.','playbooks','Users','public','listed',false)
  ON CONFLICT (slug) DO NOTHING RETURNING id INTO _item;
  IF _item IS NOT NULL THEN
    INSERT INTO public.marketplace_item_versions (item_id,semver,status,payload_class,install_manifest,published_at)
    VALUES (_item,'1.0.0','published','config_only', '{"kb_pack": {"docs": [{"title": "Designing Between-Session Accountability", "category": "playbooks", "tags": ["accountability", "commitments", "between-sessions"], "content": "Most results are won or lost between meetings, not in them. Your job is to design the container so the client keeps momentum when you''re not in the room.\n\nStart every session close with a commitment that passes three tests: it''s specific (a verb and an object, not \"work on the deck\"), it''s small enough to finish before you meet again, and the client named it out loud in their own words. A commitment you assigned is a task; one they authored is a decision. Only the second one sticks.\n\nAttach three things to each commitment: a by-when date, a done-looks-like definition, and a single point of visible proof — a link, a screenshot, a one-line reply. Proof beats a verbal \"yeah, I did it\" because it makes progress observable to both of you.\n\nCalibrate the load. One meaningful commitment beats five they''ll abandon. If a client repeatedly overcommits and underdelivers, that''s data — cut the list, don''t add pressure.\n\nName the obstacle before they leave: \"What''s most likely to get in the way, and what will you do when it does?\" Pre-deciding the response to friction is the single highest-return move in accountability work.\n\nRecord commitments where both of you can see them between sessions. The record is the accountability; memory is not. Open the next session by reviewing it first — every time, without exception — so the client learns that what they commit to is what you''ll return to."}, {"title": "The Follow-Through Nudge Cadence", "category": "playbooks", "tags": ["follow-up", "cadence", "nudges"], "content": "A commitment with no touchpoint between sessions decays fast. A well-timed nudge is not nagging — it''s the reminder that someone is paying attention, which is exactly what most clients are paying you for.\n\nUse a three-beat cadence around each commitment. Beat one, the day after the session: a short recap of what they committed to, in their words, so it''s on record while it''s fresh. Beat two, at the midpoint before the next meeting: a light check — \"How''s the client outreach going? Anything in the way?\" Open, not accusatory. Beat three, 24 hours before you meet: a heads-up that you''ll review it, which gives an honest client time to close the loop and a stuck client permission to flag they''re stuck.\n\nMatch the channel to the weight. A quick text or chat message for a light check; a longer note when they need to think. Never make a low-stakes nudge feel like a summons.\n\nWrite nudges that assume good faith. \"Wanted to make sure you had what you needed\" lands better than \"Did you do it yet?\" The first keeps the relationship warm; the second turns you into their boss.\n\nCritically: read the response, and stop nudging once they''ve delivered or clearly re-committed. A cadence that fires regardless of what the client did feels robotic and erodes trust. The point is attention, and attention adapts. When a client consistently follows through without prompts, thin the cadence — earned autonomy is a milestone worth marking."}, {"title": "When a Client Goes Quiet — A Re-Engagement Ladder", "category": "playbooks", "tags": ["re-engagement", "at-risk", "retention"], "content": "Silence is information, not an insult. A client who''s gone dark is usually stuck, embarrassed, overwhelmed, or reconsidering — rarely done with you. Climb a ladder, escalating warmth and lowering the ask at each rung, and stop the moment they respond.\n\nRung one, the light touch (a few days quiet): a low-pressure, no-ask message. \"Thinking about your launch — no need to reply, just here when you''re ready.\" This removes the obligation that silence often creates.\n\nRung two, the specific hook (a week or so): reference something concrete from their work. \"Did the pricing conversation with your client happen?\" Specificity signals you remember them, not just their invoice.\n\nRung three, the honest check (10–14 days): name it kindly and give them an easy exit. \"Noticed we''ve lost our rhythm — totally normal. Want to pick back up, or is now not the time?\" Offering the off-ramp paradoxically keeps more people on.\n\nRung four, the reset offer: propose a fresh start with a shrunk scope. \"Let''s forget the backlog and just pick one thing to move this week.\" Guilt about missed commitments is a top cause of ghosting; clearing the slate removes it.\n\nTwo rules govern the whole ladder. Never send the next rung if they''ve replied — respond to the human, not the sequence. And log the pattern: a client who needs the ladder twice needs a direct conversation about fit, not a third climb."}]}, "functions": []}'::jsonb, now()) RETURNING id INTO _ver;
    UPDATE public.marketplace_items SET current_version_id=_ver WHERE id=_item;
  END IF;
END $seed$;

DO $seed$
DECLARE _vendor uuid; _item uuid; _ver uuid;
BEGIN
  SELECT id INTO _vendor FROM public.marketplace_vendors WHERE slug='paige';
  INSERT INTO public.marketplace_items (slug,item_type,vendor_id,origin,name,tagline,description,category,icon,scope,status,default_for_new_tenants)
  VALUES ('group_program_facilitation','kb_pack',_vendor,'first_party','Group Program Facilitation','Run a cohort so every seat feels like a front-row seat.','A facilitator''s playbook for onboarding cohorts, sustaining week-over-week engagement, and managing the quiet and dominant voices in group programs.','playbooks','Users','public','listed',false)
  ON CONFLICT (slug) DO NOTHING RETURNING id INTO _item;
  IF _item IS NOT NULL THEN
    INSERT INTO public.marketplace_item_versions (item_id,semver,status,payload_class,install_manifest,published_at)
    VALUES (_item,'1.0.0','published','config_only', '{"kb_pack": {"docs": [{"title": "Onboarding a Cohort vs a 1:1 Client", "category": "playbooks", "tags": ["onboarding", "cohort", "group-programs"], "content": "Onboarding a group is not onboarding one client five times. In 1:1 work you''re building a private relationship; in a cohort you''re building a room. Get the room right in week one or you spend the rest of the program fighting drift.\n\nThe first job is belonging, not content. People decide in the opening session whether this is a place they''ll show up for. Open with a structured round where every person speaks early — their name, their situation, and one specific outcome they want. Early voice predicts sustained participation; someone who stays silent in session one is your first at-risk flag.\n\nSet the norms explicitly, because a group without stated norms defaults to whoever is loudest. Cover the essentials out loud: how to ask for help, what confidentiality means here, expected prep, and how you''ll handle people who fall behind. Written norms give you something to point back to later without singling anyone out.\n\nHandle logistics as a batch — schedule, materials access, where conversation happens between sessions — so individual confusion doesn''t eat live time. In 1:1 you can improvise the admin; in a group, unclear logistics multiply across every member.\n\nStill, protect a thread of the personal. Collect each member''s specific goal before the program starts and reference it by name during sessions. The paradox of good group facilitation: people commit to the collective only when they feel individually seen inside it. Scale the belonging; never scale away the individual."}, {"title": "Keeping a Group Engaged Week Over Week", "category": "playbooks", "tags": ["engagement", "retention", "facilitation"], "content": "Cohort energy decays on a predictable curve: high at the start, a slump in the middle third, a rally near the end if you''ve built one. Your job is to flatten the slump, and that''s a design problem you solve before it hits, not a motivation problem you fix after.\n\nOpen every session by making progress visible. Have two or three members share a concrete win from the week — not you recapping, them reporting. Peer proof that the work works is more persuasive than anything you can say, and it quietly pressures the quiet members to have something to share next time.\n\nGive people a reason to return that isn''t just the next lesson. A running challenge, a peer-accountability pairing, a between-session prompt that surfaces in the room — engagement lives in the gaps between sessions as much as inside them. A member who interacts mid-week arrives warm.\n\nWatch attendance and participation as a leading indicator, not a lagging one. The member who misses two sessions or stops posting is usually gone before they formally quit. Reach out privately and specifically the moment the pattern shows — \"missed you the last two weeks, everything alright?\" — while re-engagement is still cheap.\n\nVary the format so the room never feels like a rerun: teaching, hot seats, small-group breakouts, peer review, Q&A. Predictable structure with variable texture is the formula — people want to know what kind of thing is coming without knowing exactly what will happen. Sameness is what kills the middle third."}, {"title": "Managing the Quiet and the Dominant Participant", "category": "playbooks", "tags": ["facilitation", "group-dynamics", "participation"], "content": "Every cohort has both, and they''re linked: the dominant participant often creates the quiet one. Airtime is a fixed resource, and when a few voices spend it all, the rest stop reaching for it. Managing participation is really managing the distribution of airtime — and that''s the facilitator''s job, not the group''s.\n\nFor the dominant participant, assume good intent — they''re usually engaged, not malicious — and redirect rather than shut down. Use structure that spreads voice without confrontation: \"Let''s hear from someone we haven''t heard from yet,\" or timed rounds where everyone gets the same window. Redirecting the room protects the individual''s dignity while reclaiming the space. If it persists, a warm private word — \"your energy is great; I want to make sure the quieter folks pull from it too\" — turns a dominator into an ally.\n\nFor the quiet participant, lower the cost of speaking. Cold-calling raises it; invitation lowers it. Use low-stakes on-ramps — a one-word check-in, a written response everyone shares, small breakouts where speaking to two people is easier than speaking to twenty. Many quiet members are processing, not disengaged; give them a beat and a smaller room.\n\nDistinguish quiet-and-fine from quiet-and-fading. Silence plus falling attendance and no submitted work is a retention risk; reach out privately. Silence from an otherwise-engaged member who does the work is just a temperament — respect it, offer written channels, and don''t perform-manage an introvert into leaving.\n\nThe standard to hold: a healthy group is one where the shy feel safe to speak and the loud feel useful, not policed. You engineer that balance every session; it does not happen on its own."}]}, "functions": []}'::jsonb, now()) RETURNING id INTO _ver;
    UPDATE public.marketplace_items SET current_version_id=_ver WHERE id=_item;
  END IF;
END $seed$;

COMMIT;
